int main() {
    // Read 16 bytes from temp_data.bin
    FILE *file = fopen("temp_data.bin", "rb");
    if (!file) {
        fprintf(stderr, "Failed to open temp_data.bin\n");
        return 1;
    }

    uint8_t data[16];
    size_t bytes_read = fread(data, 1, 16, file);
    fclose(file);

    if (bytes_read != 16) {
        fprintf(stderr, "Failed to read 16 bytes, got %zu\n", bytes_read);
        return 1;
    }

    // Load the shared library
    void *handle = dlopen("./libcompute.so", RTLD_LAZY);
    if (!handle) {
        fprintf(stderr, "Failed to load libcompute.so: %s\n", dlerror());
        return 1;
    }

    // Get the transform function
    int64_t (*transform)(const uint8_t*) = dlsym(handle, "transform");
    if (!transform) {
        fprintf(stderr, "Failed to find transform function: %s\n", dlerror());
        dlclose(handle);
        return 1;
    }

    // Call the transform function
    int64_t result = transform(data);

    // Print the result
    printf("%ld\n", result);

    // Clean up
    dlclose(handle);
    return 0;
}
